import { Component, OnInit, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { ResumeService } from '../../core/services/resume.service';
import { HistoryItem } from '../../core/models/resume.model';

@Component({
  selector: 'app-history',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './history.component.html',
  styleUrl: './history.component.scss'
})
export class HistoryComponent implements OnInit {
  private resumeService = inject(ResumeService);
  private router = inject(Router);

  historyItems = signal<HistoryItem[]>([]);
  isLoading = signal(true);
  errorMessage = signal<string | null>(null);

  ngOnInit() {
    this.loadHistory();
  }

  loadHistory() {
    this.isLoading.set(true);
    this.errorMessage.set(null);

    this.resumeService.getHistory().subscribe({
      next: (items) => {
        this.historyItems.set(items);
        this.isLoading.set(false);
      },
      error: (error) => {
        this.errorMessage.set('Failed to load history. Please try again.');
        this.isLoading.set(false);
      }
    });
  }

  viewDetails(id: string) {
    this.router.navigate(['/history', id]);
  }

  deleteItem(id: string, event: Event) {
    event.stopPropagation();
    
    if (!confirm('Are you sure you want to delete this analysis?')) {
      return;
    }

    this.resumeService.deleteHistory(id).subscribe({
      next: () => {
        this.historyItems.update(items => items.filter(item => item.id !== id));
      },
      error: (error) => {
        this.errorMessage.set('Failed to delete analysis. Please try again.');
      }
    });
  }

  getScoreColor(score: number): string {
    if (score > 70) return 'success';
    if (score >= 40) return 'warning';
    return 'danger';
  }

  getVerdict(score: number): string {
    if (score > 85) return 'Strong Match';
    if (score > 70) return 'Good Match';
    if (score >= 40) return 'Partial Match';
    return 'Weak Match';
  }

  getVerdictClass(score: number): string {
    if (score > 85) return 'strong';
    if (score > 70) return 'good';
    if (score >= 40) return 'partial';
    return 'weak';
  }

  formatDate(dateString: string): string {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', { 
      month: 'short', 
      day: 'numeric', 
      year: 'numeric' 
    });
  }
}
<div class="history-container">
  <h1 class="page-title">Analysis History</h1>

  <!-- Error Message -->
  <div *ngIf="errorMessage()" class="error-alert">
    {{ errorMessage() }}
  </div>

  <!-- Loading State -->
  <div *ngIf="isLoading()" class="loading-grid">
    <div class="skeleton-card" *ngFor="let i of [1,2,3,4,5,6]"></div>
  </div>

  <!-- Empty State -->
  <div *ngIf="!isLoading() && historyItems().length === 0" class="empty-state">
    <svg width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1">
      <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
      <polyline points="14 2 14 8 20 8"></polyline>
      <line x1="16" y1="13" x2="8" y2="13"></line>
      <line x1="16" y1="17" x2="8" y2="17"></line>
      <polyline points="10 9 9 9 8 9"></polyline>
    </svg>
    <h2>No Analysis History</h2>
    <p>You haven't analyzed any resumes yet. Start by uploading a resume!</p>
    <a routerLink="/analyzer" class="cta-button">Analyze Resume</a>
  </div>

  <!-- History Grid -->
  <div *ngIf="!isLoading() && historyItems().length > 0" class="history-grid">
    <div *ngFor="let item of historyItems()" class="history-card" (click)="viewDetails(item.id)">
      <div class="card-header">
        <div class="file-icon">
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
            <polyline points="14 2 14 8 20 8"></polyline>
          </svg>
        </div>
        <button class="delete-btn" (click)="deleteItem(item.id, $event)" title="Delete">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <polyline points="3 6 5 6 21 6"></polyline>
            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
          </svg>
        </button>
      </div>

      <h3 class="file-name">{{ item.fileName }}</h3>

      <div class="score-display">
        <span class="score-number" [ngClass]="getScoreColor(item.score)">{{ item.score }}</span>
        <span class="score-label">Match Score</span>
      </div>

      <div class="verdict-badge" [ngClass]="getVerdictClass(item.score)">
        {{ getVerdict(item.score) }}
      </div>

      <div class="card-footer">
        <span class="date">{{ formatDate(item.createdAt) }}</span>
        <button class="view-btn">View Details →</button>
      </div>
    </div>
  </div>
</div>
